1	type Item = { type: string; cursed?: boolean; enchantment?: number };
2	type Damage = { itemType: string; amount: number };
3	type Incident = { cause?: string; damages: Damage[] };
4	type QuoteStep = { op?: "quote"; items: Item[] };
5	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
6	type Step = QuoteStep | ClaimStep;
7	type Scenario = { customer?: { yearsWithMHPCO?: number }; steps: Step[] };
8	
9	const PROCESSING_FEE = 5;
10	const COMPONENT_BASE_PER_ITEM = 25;
11	const COMPONENT_BLOCK_OF_THREE_BASE = 60;
12	
13	const CURSED_SURCHARGE_RATE = 0.5;
14	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
15	const FIRST_INSURANCE_MARKUP_RATE = 0.1;
16	const LOYALTY_DISCOUNT_RATE = 0.2;
17	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
18	const LOYALTY_YEARS_THRESHOLD = 2;
19	const HIGH_ENCHANTMENT_THRESHOLD = 5;
20	
21	const CLAIM_DEDUCTIBLE = 100;
22	const CAP_MULTIPLIER = 2;
23	
24	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
25	  sword: 100,
26	  amulet: 60,
27	  staff: 80,
28	  potion: 40,
29	};
30	
31	const INSURANCE_VALUE_BY_TYPE: Record<string, number> = {
32	  sword: 1000,
33	  amulet: 600,
34	  rune: 250,
35	};
36	
37	type PolicyState = { items: Item[]; remainingCap: number };
38	
39	export function runScenario(input: unknown): unknown {
40	  const { customer, steps } = input as Scenario;
41	  const years = customer?.yearsWithMHPCO ?? 0;
42	  const policies: Record<number, PolicyState> = {};
43	  const results = steps.map((step, index) => {
44	    if (step.op === "claim") return computeClaim(step, policies);
45	    const isFollowUp = index >= 1;
46	    policies[index] = { items: step.items, remainingCap: CAP_MULTIPLIER * insuranceSumFor(step.items) };
47	    return { premium: computePremium(step.items, years, isFollowUp) };
48	  });
49	  return { results };
50	}
51	
52	function insuranceSumFor(items: Item[]): number {
53	  return items.reduce((sum, item) => sum + INSURANCE_VALUE_BY_TYPE[item.type], 0);
54	}
55	
56	function computeClaim(step: ClaimStep, policies: Record<number, PolicyState>): { payout: number; remainingCap: number } {
57	  const policy = policies[step.policy];
58	  const payout = step.incident.damages.reduce(
59	    (sum, damage) => sum + Math.max(0, damage.amount - CLAIM_DEDUCTIBLE),
60	    0,
61	  );
62	  policy.remainingCap -= payout;
63	  return { payout, remainingCap: policy.remainingCap };
64	}
65	
66	function computePremium(items: Item[], years: number, isFollowUp: boolean): number {
67	  if (items.length === 0) return PROCESSING_FEE;
68	  if (items.every(isComponent)) return componentsPremium(items);
69	  return mainItemsPremium(items, years, isFollowUp);
70	}
71	
72	function mainItemsPremium(items: Item[], years: number, isFollowUp: boolean): number {
73	  const policyBase = items.reduce((sum, item) => sum + BASE_PREMIUM_BY_TYPE[item.type], 0);
74	  const itemSubtotalSum = items.reduce((sum, item) => sum + itemSubtotal(item), 0);
75	  const policyMod = (cond: boolean, rate: number) => (cond ? policyBase * rate : 0);
76	  const loyaltyDiscount = policyMod(years >= LOYALTY_YEARS_THRESHOLD, LOYALTY_DISCOUNT_RATE);
77	  const followUpDiscount = policyMod(isFollowUp, FOLLOW_UP_DISCOUNT_RATE);
78	  return Math.ceil(itemSubtotalSum - loyaltyDiscount - followUpDiscount) + PROCESSING_FEE;
79	}
80	
81	function itemSubtotal(item: Item): number {
82	  const base = BASE_PREMIUM_BY_TYPE[item.type];
83	  const surchargeIf = (cond: boolean, rate: number) => (cond ? base * rate : 0);
84	  const cursedSurcharge = surchargeIf(item.cursed === true, CURSED_SURCHARGE_RATE);
85	  const highEnchSurcharge = surchargeIf(isHighlyEnchanted(item), HIGH_ENCHANTMENT_SURCHARGE_RATE);
86	  const firstInsuranceMarkup = base * FIRST_INSURANCE_MARKUP_RATE;
87	  return base + cursedSurcharge + highEnchSurcharge + firstInsuranceMarkup;
88	}
89	
90	function isHighlyEnchanted(item: Item): boolean {
91	  return (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
92	}
93	
94	function componentsPremium(items: Item[]): number {
95	  const runes = items.filter((i) => i.type === "rune").length;
96	  const moonstones = items.filter((i) => i.type === "moonstone").length;
97	  return premiumFromBase(componentTypeBase(runes) + componentTypeBase(moonstones));
98	}
99	
100	function componentTypeBase(count: number): number {
101	  return count === 3 ? COMPONENT_BLOCK_OF_THREE_BASE : count * COMPONENT_BASE_PER_ITEM;
102	}
103	
104	function isComponent(item: Item): boolean {
105	  return item.type === "rune" || item.type === "moonstone";
106	}
107	
108	function premiumFromBase(base: number): number {
109	  return Math.ceil((base * 11) / 10) + PROCESSING_FEE;
110	}
